contracts/CircuitPool.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";
import "@openzeppelin/contracts/security/ReentrancyGuard.sol";
import "./CircuitRegistry.sol";

/**
 * Lending pool: holds USDT, lets registered agents draw and repay.
 * Uses SafeERC20 and CEI pattern; ReentrancyGuard on all state-changing paths.
 */
contract CircuitPool is ReentrancyGuard {
    using SafeERC20 for IERC20;

    IERC20 public immutable token;
    CircuitRegistry public immutable registry;

    event Draw(bytes32 indexed agentId, address indexed to, uint256 amount);
    event Repay(bytes32 indexed agentId, address indexed from, uint256 amount);
    event Deposited(address indexed from, uint256 amount);

    /// @param _token ERC20 token (e.g. USDT) for deposits and draws.
    /// @param _registry CircuitRegistry that authorizes agents.
    constructor(address _token, address _registry) {
        require(_token != address(0), "CircuitPool: zero token");
        require(_registry != address(0), "CircuitPool: zero registry");
        token = IERC20(_token);
        registry = CircuitRegistry(_registry);
    }

    /// @notice LP deposits token into the pool. No cap; use CEI + SafeERC20.
    /// @param amount Amount to deposit (must be approved by caller).
    function deposit(uint256 amount) external nonReentrant {
        require(amount > 0, "CircuitPool: zero amount");
        token.safeTransferFrom(msg.sender, address(this), amount);
        emit Deposited(msg.sender, amount);
    }

    /// @notice Risk cap: max 5% of pool TVL per agent, max 20% per operator (per CIRCUIT Bible).
    uint256 public constant MAX_PCT_PER_AGENT = 5;
    uint256 public constant MAX_PCT_PER_OPERATOR = 20;
    uint256 public constant PCT_DENOMINATOR = 100;

    /// @notice Agent wallet draws up to credit limit, subject to 5% per agent and 20% per operator of pool TVL.
    /// @param agentId Agent id from CircuitRegistry.
    /// @param to Recipient of the drawn amount.
    /// @param amount Amount to draw (6 decimals for USDT).
    function draw(bytes32 agentId, address to, uint256 amount) external nonReentrant {
        require(to != address(0), "CircuitPool: zero to");
        (address wallet, address operator, uint256 creditLimit, uint256 drawn, , bool active) = registry.getAgent(agentId);
        require(active, "CircuitPool: inactive agent");
        require(msg.sender == wallet, "CircuitPool: only agent wallet");
        require(amount > 0, "CircuitPool: zero amount");
        require(drawn + amount <= creditLimit, "CircuitPool: over limit");

        uint256 poolTVL = token.balanceOf(address(this));
        require(poolTVL > 0, "CircuitPool: no liquidity");
        require(amount <= (poolTVL * MAX_PCT_PER_AGENT) / PCT_DENOMINATOR, "CircuitPool: over 5% per agent");
        uint256 operatorDrawn = registry.totalDrawnByOperator(operator);
        require(operatorDrawn + amount <= (poolTVL * MAX_PCT_PER_OPERATOR) / PCT_DENOMINATOR, "CircuitPool: over 20% per operator");

        registry.updateDrawn(agentId, amount);
        token.safeTransfer(to, amount);

        emit Draw(agentId, to, amount);
    }

    /// @notice Agent wallet repays drawn amount. Cannot repay more than currently drawn.
    /// @param agentId Agent id from CircuitRegistry.
    /// @param amount Amount to repay (must be approved by caller).
    function repay(bytes32 agentId, uint256 amount) external nonReentrant {
        (address wallet, , , uint256 drawn, , ) = registry.getAgent(agentId);
        require(msg.sender == wallet, "CircuitPool: only agent wallet");
        require(amount > 0, "CircuitPool: zero amount");
        require(amount <= drawn, "CircuitPool: repay over drawn");

        registry.updateRepaid(agentId, amount);
        token.safeTransferFrom(msg.sender, address(this), amount);

        emit Repay(agentId, msg.sender, amount);
    }

    function poolBalance() external view returns (uint256) {
        return token.balanceOf(address(this));
    }
}

contracts/CircuitRegistry.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

/**
 * Registers agent wallets and links them to an operator.
 * Used by CIRCUIT to know which addresses are agents and who operates them.
 */
contract CircuitRegistry {
    struct Agent {
        address wallet;
        address operator;
        uint256 creditLimit;
        uint256 drawn;
        uint8 riskTier; // 1=A, 2=B, 3=C
        bool active;
        uint256 registeredAt;
    }

    mapping(bytes32 => Agent) public agentsById;
    mapping(address => bytes32) public agentIdByWallet;
    mapping(address => bytes32[]) public agentIdsByOperator;
    /// @dev Total drawn across all agents of an operator (for 20% risk cap).
    mapping(address => uint256) public totalDrawnByOperator;

    uint256 public nextAgentNonce;
    address public pool;

    event AgentRegistered(bytes32 indexed agentId, address indexed wallet, address indexed operator, uint256 creditLimit, uint8 riskTier);
    event CreditLimitUpdated(bytes32 indexed agentId, uint256 newLimit);
    event AgentDeactivated(bytes32 indexed agentId);

    modifier onlyPool() {
        require(msg.sender == pool, "CircuitRegistry: only pool");
        _;
    }

    /// @notice Set the CircuitPool address once. Only callable before pool is set.
    /// @param _pool Address of the CircuitPool contract.
    function setPool(address _pool) external {
        require(_pool != address(0), "CircuitRegistry: zero pool");
        require(pool == address(0), "CircuitRegistry: pool already set");
        pool = _pool;
    }

    /// @notice Register a new agent wallet under the caller (operator). One wallet per agent.
    /// @param agentWallet Address that will be able to draw/repay (agent wallet).
    /// @param creditLimit Max total drawn at any time for this agent.
    /// @param riskTier 1=A, 2=B, 3=C (for scoring/display).
    /// @return agentId Unique id for this agent (keccak256(operator, wallet, chainId, nonce)).
    function registerAgent(
        address agentWallet,
        uint256 creditLimit,
        uint8 riskTier
    ) external returns (bytes32 agentId) {
        require(agentWallet != address(0), "CircuitRegistry: zero wallet");
        require(agentIdByWallet[agentWallet] == bytes32(0), "CircuitRegistry: already registered");
        require(riskTier >= 1 && riskTier <= 3, "CircuitRegistry: invalid risk tier");

        agentId = keccak256(abi.encodePacked(msg.sender, agentWallet, block.chainid, nextAgentNonce));
        nextAgentNonce++;

        agentsById[agentId] = Agent({
            wallet: agentWallet,
            operator: msg.sender,
            creditLimit: creditLimit,
            drawn: 0,
            riskTier: riskTier,
            active: true,
            registeredAt: block.timestamp
        });
        agentIdByWallet[agentWallet] = agentId;
        agentIdsByOperator[msg.sender].push(agentId);

        emit AgentRegistered(agentId, agentWallet, msg.sender, creditLimit, riskTier);
        return agentId;
    }

    function getAgent(bytes32 agentId) external view returns (
        address wallet,
        address operator,
        uint256 creditLimit,
        uint256 drawn,
        uint8 riskTier,
        bool active
    ) {
        Agent storage a = agentsById[agentId];
        return (a.wallet, a.operator, a.creditLimit, a.drawn, a.riskTier, a.active);
    }

    function getAgentIdsByOperator(address operator) external view returns (bytes32[] memory) {
        return agentIdsByOperator[operator];
    }

    /// @notice Called by pool when an agent draws. Updates drawn and operator total for 20% cap.
    /// @param agentId Agent that drew.
    /// @param addDrawn Amount added to drawn (must keep drawn <= creditLimit).
    function updateDrawn(bytes32 agentId, uint256 addDrawn) external onlyPool {
        Agent storage a = agentsById[agentId];
        require(a.active, "CircuitRegistry: inactive");
        a.drawn += addDrawn;
        require(a.drawn <= a.creditLimit, "CircuitRegistry: over limit");
        totalDrawnByOperator[a.operator] += addDrawn;
    }

    /// @notice Called by pool when an agent repays. Reduces drawn and operator total.
    /// @param agentId Agent that repaid.
    /// @param repaid Amount subtracted from drawn (must be <= current drawn).
    function updateRepaid(bytes32 agentId, uint256 repaid) external onlyPool {
        Agent storage a = agentsById[agentId];
        require(a.drawn >= repaid, "CircuitRegistry: repay over drawn");
        a.drawn -= repaid;
        totalDrawnByOperator[a.operator] -= repaid;
    }

    function setCreditLimit(bytes32 agentId, uint256 newLimit) external onlyPool {
        Agent storage a = agentsById[agentId];
        a.creditLimit = newLimit;
        emit CreditLimitUpdated(agentId, newLimit);
    }

    function deactivate(bytes32 agentId) external onlyPool {
        agentsById[agentId].active = false;
        emit AgentDeactivated(agentId);
    }
}

contracts/MockUSDT.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/token/ERC20/ERC20.sol";
import "@openzeppelin/contracts/access/Ownable.sol";

/**
 * Testnet-only mintable USDT. 6 decimals (same as mainnet USDT).
 * Includes a permissionless faucet for LPs and beta testers.
 * FOR SEPOLIA DEMO ONLY — do not use in production.
 */
contract MockUSDT is ERC20, Ownable {
    uint256 public constant FAUCET_AMOUNT = 10_000 * 1e6; // 10,000 USDT (6 decimals)
    uint256 public constant FAUCET_COOLDOWN = 1 days;

    mapping(address => uint256) public lastFaucetAt;

    event FaucetRequested(address indexed to, uint256 amount);

    constructor() ERC20("Mock USDT", "USDT") Ownable() {}

    function decimals() public pure override returns (uint8) {
        return 6;
    }

    /// @notice Owner mints supply (e.g. to pool and to this contract for faucet reserve).
    function mint(address to, uint256 amount) external onlyOwner {
        require(to != address(0), "MockUSDT: mint to zero");
        require(amount > 0, "MockUSDT: zero amount");
        _mint(to, amount);
    }

    /// @notice Any address can request test USDT once per cooldown period. Reserve must be minted to this contract by owner.
    function requestFaucet() external {
        require(block.timestamp >= lastFaucetAt[msg.sender] + FAUCET_COOLDOWN, "MockUSDT: cooldown");
        require(balanceOf(address(this)) >= FAUCET_AMOUNT, "MockUSDT: faucet empty");
        lastFaucetAt[msg.sender] = block.timestamp;
        _transfer(address(this), msg.sender, FAUCET_AMOUNT);
        emit FaucetRequested(msg.sender, FAUCET_AMOUNT);
    }

    /// @notice Next timestamp when the given address can request faucet again.
    function nextFaucetAt(address account) external view returns (uint256) {
        return lastFaucetAt[account] + FAUCET_COOLDOWN;
    }
}

